/**
 * LegalDocumentFormModal Component
 *
 * Wraps the LegalDocumentForm in a Material UI Dialog for modal display.
 * Use this component when you want to show the form in a popup dialog.
 *
 * @example
 * ```tsx
 * <LegalDocumentFormModal
 *   open={isModalOpen}
 *   onClose={handleClose}
 *   onSubmit={handleCreate}
 *   onCancel={handleClose}
 *   isLoading={isCreating}
 * />
 * ```
 */
export function LegalDocumentFormModal({
  open,
  onClose,
  title,
  legalDocument,
  onSubmit,
  onCancel,
  isLoading = false,
  className = '',
}: LegalDocumentFormModalProps): React.ReactElement {
  const isEditMode = Boolean(legalDocument);
  const modalTitle = title ?? (isEditMode ? 'Edit LegalDocument' : 'Create LegalDocument');

  // Handle modal close - prevent closing during loading
  const handleClose = () => {
    if (!isLoading) {
      onClose();
    }
  };

  return (
    <Dialog
      open={open}
      onClose={handleClose}
      maxWidth="md"
      fullWidth
      data-testid="modal-legal_document-form"
    >
      <DialogTitle sx={{ m: 0, p: 2, display: "flex", justifyContent: "space-between", alignItems: "center" }}>
        {modalTitle}
        <IconButton
          aria-label="close"
          onClick={handleClose}
          disabled={isLoading}
          data-testid="modal-close-button"
          sx={{ color: (theme) => theme.palette.grey[500] }}
        >
          <CloseIcon />
        </IconButton>
      </DialogTitle>
      <DialogContent dividers>
        <LegalDocumentForm
          legalDocument={legalDocument}
          onSubmit={onSubmit}
          onCancel={onCancel}
          isLoading={isLoading}
          className={className}
        />
      </DialogContent>
    </Dialog>
  );
}


